const json=$input.first().json;
const raw=(json.chatInput||json.input||json.message||json.text||json.userMessage||'').trim();
const msg=raw.replace(/^\[\s*/,'').replace(/\s*\]$/,'').trim();
const canon=function(s){s=s.toUpperCase();return /^\d+$/.test(s)?s.padStart(8,'0'):s;};
if(msg.toLowerCase()==='list')return[{json:{mode:'list'}}];
const rem=msg.match(/^remove\s+([A-Z0-9]{6,8})$/i);
if(rem)return[{json:{mode:'remove',companyNumber:canon(rem[1])}}];
const upd=msg.match(/^update\s+([A-Z0-9]{6,8})\s+(.+)$/i);
if(upd){
  const companyNumber=canon(upd[1]);
  const fieldsRaw=upd[2].split('|').map(function(s){return s.trim();}).filter(Boolean);
  const updates=[];
  const fieldErrors=[];
  for(let i=0;i<fieldsRaw.length;i++){
    const fm=fieldsRaw[i].match(/^([^=]+?)\s*=\s*(.+)$/);
    if(!fm){fieldErrors.push('Cannot parse field "'+fieldsRaw[i]+'"');continue;}
    updates.push({field:fm[1].trim(),value:fm[2].trim()});
  }
  if(updates.length===0){
    throw new Error((fieldErrors.length?fieldErrors.join('; '):'No valid field updates found.')+' Format: update <RegNo> <Field>=<Value> | <Field>=<Value>');
  }
  return[{json:{mode:'update',companyNumber:companyNumber,updates:updates}}];
}
const expanded=msg.replace(/\s+(?=add\s+[A-Z]{0,2}\d{6,8}\s)/gi,'\n');
const lines=expanded.split(/\r?\n/).map(function(l){return l.trim();}).filter(Boolean);
const results=[];
const errors=[];
for(let i=0;i<lines.length;i++){
  const line=lines[i];
  const parts=line.match(/^add\s+([A-Z0-9]{6,8})\s+(\d{1,2})\s+(.+)$/i);
  if(!parts){const noRank=line.match(/^add\s+([A-Z0-9]{6,8})(?:\s|$)/i);errors.push('Line '+(i+1)+': '+(noRank?'missing ranking (1-2 digits) after company number '+canon(noRank[1]):'cannot parse "'+line+'"'));continue;}
  const pipeParts=parts[3].split('|');
  const products=pipeParts[0].split(',').map(function(p){return p.trim();}).filter(Boolean);
  const note=pipeParts.length>1?pipeParts.slice(1).join('|').trim():'';
  results.push({json:{mode:'add',companyNumber:canon(parts[1]),ranking:Number(parts[2]),products:products,note:note}});
}
if(results.length===0){
  const hint=errors.length>0?errors.join('; '):'No valid commands found.';
  throw new Error(hint+' Format: add <RegNo> <Ranking> <Products> | <Note>');
}
results[0].json.parseReport='Adds parsed ('+results.length+'): '+results.map(function(r){return r.json.companyNumber;}).join(', ')+(errors.length?' | SKIPPED '+errors.length+': '+errors.join('; '):'');
return results;

const resp=$input.first().json;
const hdrs=resp.headers||{};
const s3Url=hdrs.location||hdrs.Location||null;
return[{json:{s3Url:s3Url}}];

try {
  const raw = ($input.first().json || {}).data;
  if (!raw) return [{ json: { ollamaBody: null, hasImages: false, debug: 'no data from download' } }];
  const content = String(raw).substring(0, 800000);

  // ---- 1. Parse contexts, capturing any dimension members ----
  const ctxMap = {};
  const ctxRe = /<xbrli:context\s+id="([^"]+)"([\s\S]*?)<\/xbrli:context>/gi;
  let cm;
  while ((cm = ctxRe.exec(content)) !== null) {
    const id = cm[1];
    const bodyc = cm[2];
    const em = bodyc.match(/<xbrli:endDate>\s*([^<]+?)\s*<\/xbrli:endDate>/i);
    const im = bodyc.match(/<xbrli:instant>\s*([^<]+?)\s*<\/xbrli:instant>/i);
    const dims = [];
    const dre = /dimension="([^"]+)"[^>]*>\s*([^<]+?)\s*<\/xbrldi:explicitMember>/gi;
    let dm;
    while ((dm = dre.exec(bodyc)) !== null) {
      dims.push({ dim: dm[1].split(':').pop(), member: dm[2].split(':').pop() });
    }
    ctxMap[id] = { end: em ? em[1].trim() : null, instant: im ? im[1].trim() : null, dims: dims };
  }

  // ---- 2. Group-parent detection: presence of a Consolidated member ----
  let isGroupParent = false;
  for (const id in ctxMap) {
    for (const d of ctxMap[id].dims) {
      if (/Consolidated/i.test(d.member)) { isGroupParent = true; break; }
    }
    if (isGroupParent) break;
  }

  // ---- 3. Latest period end across all contexts ----
  let latestEnd = null;
  for (const id in ctxMap) {
    const d = ctxMap[id].end || ctxMap[id].instant;
    if (d && (!latestEnd || d > latestEnd)) latestEnd = d;
  }

  // A context is usable for a headline figure only if it carries no breakdown
  // dimension. The group/company split and currency are allowed; anything else
  // (equity class, PPE class, subsidiary, maturity, ...) is a partial breakdown.
  function classify(c) {
    for (const d of c.dims) {
      if (!/GroupCompanyData|Currencies/i.test(d.dim)) return null;
    }
    for (const d of c.dims) {
      if (/GroupCompanyData/i.test(d.dim)) return /Consolidated/i.test(d.member) ? 'group' : 'company';
    }
    return 'undim';
  }
  function rankedCtxIds(isInstant) {
    const buckets = { group: [], undim: [], company: [] };
    for (const id in ctxMap) {
      const c = ctxMap[id];
      const d = isInstant ? c.instant : c.end;
      if (d !== latestEnd) continue;
      const k = classify(c);
      if (k) buckets[k].push(id);
    }
    const order = isGroupParent ? ['group', 'undim', 'company'] : ['company', 'undim', 'group'];
    let out = [];
    for (const k of order) out = out.concat(buckets[k]);
    return out;
  }
  const periodIds = rankedCtxIds(false);
  const instantIds = rankedCtxIds(true);

  // ---- 4. Parse ix:nonFraction / ix:nonNumeric facts ----
  const elements = [];
  const reOpen = /<ix:(nonFraction|nonNumeric)\b([^>]*)>/gi;
  let om;
  while ((om = reOpen.exec(content)) !== null) {
    const tagType = om[1];
    const attrs = om[2];
    const nameM = attrs.match(/\bname="([^"]+)"/i);
    const ctxM = attrs.match(/\bcontextRef="([^"]+)"/i);
    if (!nameM || !ctxM) continue;
    const signM = attrs.match(/\bsign="([^"]+)"/i);
    const scaleM = attrs.match(/\bscale="(-?[0-9]+)"/i);
    const closeTag = '</ix:' + tagType + '>';
    const start = om.index + om[0].length;
    const end = content.indexOf(closeTag, start);
    if (end === -1) continue;
    const inner = content.substring(start, end).replace(/<[^>]+>/g, '').replace(/\s+/g, ' ').trim();
    // store by LOCAL concept name (prefix varies per filer: core:, ns5:, uk-core: ...)
    elements.push({ local: nameM[1].split(':').pop(), ctx: ctxM[1], sign: signM ? signM[1] : null, scale: scaleM ? parseInt(scaleM[1]) : 0, text: inner });
  }

  function parseNum(el) {
    if (!el || !el.text) return null;
    const t = el.text.trim();
    const isNeg = el.sign === '-' || /^\(.*\)$/.test(t);
    const clean = t.replace(/[£$€,\s()]/g, '');
    const n = parseFloat(clean);
    if (isNaN(n)) return null;
    // Some filers mis-tag whole-number facts with a negative scale (Centrebus tags
    // employees text 704 with scale -2, which would parse as 7.04). Negative scale is
    // only legitimate on Pure-unit percentages, which are displayed with decimals
    // (e.g. 100.00) and so keep their scale via the dot check below; the headline GBP
    // and headcount concepts extracted here never legitimately use it. A mis-tagged
    // integer displayed as 704.00 would still slip through this check.
    let scale = el.scale || 0;
    if (scale < 0 && !clean.includes('.')) scale = 0;
    return (isNeg ? -n : n) * Math.pow(10, scale);
  }
  // pick the first fact matching any concept, honouring the context preference order
  function findVal(rankedIds, concepts) {
    for (const id of rankedIds) {
      for (const localName of concepts) {
        const el = elements.find(function (e) { return e.local === localName && e.ctx === id; });
        if (el) { const v = parseNum(el); if (v !== null) return v; }
      }
    }
    return null;
  }

  // ---- 5. Narrative fallback (turnover & pre-tax profit are frequently untagged) ----
  const plain = content
    .replace(/<[^>]+>/g, ' ')
    .replace(/&#160;|&nbsp;/gi, ' ')
    .replace(/&#163;|&pound;/gi, '£')
    .replace(/&amp;/gi, '&')
    .replace(/\s+/g, ' ');
  function narr(regexes) {
    for (const re of regexes) {
      const m = plain.match(re);
      if (m && m[1]) {
        const neg = /loss/i.test(m[0]);
        const n = parseFloat(m[1].replace(/,/g, ''));
        if (!isNaN(n)) return neg ? -n : n;
      }
    }
    return null;
  }
  const narrTurnover = narr([
    /turnover(?:\s+for the year)?\s+(?:of|was|were|totalled|amounted to|increased to|decreased to)\s*£?\s*([0-9]{1,3}(?:,[0-9]{3})+)/i,
    /(?:turnover|revenue)\s*£?\s*([0-9]{1,3}(?:,[0-9]{3})+)/i
  ]);
  const narrPBT = narr([
    /(?:pre-?tax\s*(?:profit|loss)?|(?:profit|loss)\s+before\s+tax(?:ation)?)\s*of\s*£?\s*([0-9]{1,3}(?:,[0-9]{3})+)/i,
    /(?:profit|loss)\s+before\s+tax(?:ation)?\s*£?\s*([0-9]{1,3}(?:,[0-9]{3})+)/i
  ]);

  // ---- 6. Assemble figures ----
  const yearEndEl = elements.find(function (e) { return e.local === 'EndDateForPeriodCoveredByReport'; });
  const yearEndText = yearEndEl ? yearEndEl.text.trim() : null;
  // prefer a 4-digit year from the structured context end date (e.g. 2024-04-30),
  // then the tagged free-text date (which may be "30.4.24")
  const yr4 = function (s) { if (!s) return null; const m = String(s).match(/\d{4}/); return m ? m[0] : null; };
  const yearEnd = yr4(latestEnd) || yr4(yearEndText) || latestEnd || yearEndText || null;

  const xbrl = {
    turnover:        findVal(periodIds, ['TurnoverRevenue', 'Turnover', 'Revenue', 'TurnoverGross']),
    employees:       findVal(periodIds, ['AverageNumberEmployeesDuringPeriod', 'AverageNumberEmployees', 'EmployeesTotal']),
    netAssets:       findVal(instantIds, ['NetAssetsLiabilities', 'Equity', 'TotalEquity']),
    profitBeforeTax: findVal(periodIds, ['ProfitLossOnOrdinaryActivitiesBeforeTax', 'ProfitLossBeforeTax', 'ProfitLossBeforeTaxation']),
    profitAfterTax:  findVal(periodIds, ['ProfitLoss', 'ProfitLossForPeriod', 'ProfitLossAttributableToOwnersOfParent']),
    yearEnd: yearEnd,
    basis: isGroupParent ? 'group' : 'company'
  };
  if (xbrl.turnover == null && narrTurnover != null) xbrl.turnover = narrTurnover;
  if (xbrl.profitBeforeTax == null && narrPBT != null) xbrl.profitBeforeTax = narrPBT;

  const numericKeys = ['turnover', 'employees', 'netAssets', 'profitBeforeTax', 'profitAfterTax'];
  const foundFields = numericKeys.filter(function (k) { return xbrl[k] != null; }).map(function (k) { return [k, xbrl[k]]; });
  const missing = numericKeys.filter(function (k) { return xbrl[k] == null; });

  // ---- 7. All present -> skip Ollama ----
  if (missing.length === 0) {
    return [{ json: { ollamaBody: null, hasImages: false, xbrlExtracted: xbrl } }];
  }

  // ---- 8. Ollama fallback for any missing fields ----
  const fmt = function (v) { return v == null ? 'null' : (v < 0 ? '-£' + Math.abs(Math.round(v)).toLocaleString() : '£' + Math.round(v).toLocaleString()); };
  const labels = { turnover: 'Turnover', employees: 'Employees', netAssets: 'Net assets', profitBeforeTax: 'Profit before tax', profitAfterTax: 'Profit after tax' };
  const preContext = foundFields.length
    ? 'Already extracted from XBRL tags / narrative (high confidence — keep unless the document clearly contradicts them):\n'
      + foundFields.map(function (kv) { return labels[kv[0]] + ': ' + (kv[0] === 'employees' ? kv[1] : fmt(kv[1])); }).join('\n') + '\n\n'
    : '';
  const basisWord = isGroupParent ? 'GROUP / CONSOLIDATED' : 'individual COMPANY (not group)';
  const prompt = 'You are reading UK company accounts from an iXBRL filing. These are ' + (isGroupParent ? 'CONSOLIDATED GROUP accounts' : 'individual COMPANY accounts') + '. Where both group and company figures are shown, use the ' + basisWord + ' figures for the CURRENT YEAR.\n\n'
    + preContext
    + 'Find or confirm these six figures:\n1. Annual turnover or revenue (GBP)\n2. Average number of employees\n3. Net assets or total equity (GBP)\n4. Profit BEFORE tax (GBP) — negative if a loss\n5. Profit AFTER tax (GBP) — negative if a loss\n6. Financial year end date\n\n'
    + 'In UK accounts, figures in parentheses e.g. (45,000) are negative. Always output negatives with a minus sign.\n\n'
    + 'Respond with ONLY these six lines:\nTurnover: £2,450,000\nEmployees: 45\nNet assets: £890,000\nProfit before tax: £150,000\nProfit after tax: £123,456\nYear: 2023\n\nIf a figure is not found, write null for that line.\n\nACCOUNTS TEXT:\n' + plain.substring(0, 120000);

  const body = JSON.stringify({ model: 'qwen3.6:27b', prompt: prompt, stream: false, think: false });
  return [{ json: { ollamaBody: body, hasImages: false, xbrlExtracted: xbrl } }];
} catch (e) {
  return [{ json: { ollamaBody: null, hasImages: false, debug: 'error: ' + String(e) } }];
}

const pages=(($input.first().json)||{}).pages||0;
const src=$('CH: Download PDF').first();
const bin=(src.binary||{}).pdfData;
if(!bin)return[{json:{pages:0,debug:'No PDF binary available'}}];
return[{json:{pages:pages},binary:{pdfData:bin}}];

const j=($input.first().json)||{};
const images=j.images||[];
if(images.length===0)return[{json:{surveyBody:null,debug:'survey conversion returned no images'}}];
const SURVEY_TOKENS_PER_PAGE=600; // measured 537 at dpi=75 on A4 portrait (prompt_eval_count 39218 / 73 pages) + ~5.5% for the 48px page-number banner; landscape or larger pages cost more
const NUM_PREDICT=16384; // generation budget - must cover the full thinking transcript (always-thinking build); 6144 truncated mid-survey on a 73-page filing
const CTX_HEADROOM=NUM_PREDICT+2048; // numCtx guarantees this much free generation space - must exceed NUM_PREDICT plus prompt text, or Ollama context-shifts and evicts image tokens
const CTX_CAP=65536;
const CTX_STEP=8192;
const maxSurveyPages=Math.floor((CTX_CAP-CTX_HEADROOM)/SURVEY_TOKENS_PER_PAGE);
if(images.length>maxSurveyPages)return[{json:{surveyBody:null,debug:'filing has '+images.length+' pages; survey cap is '+maxSurveyPages}}];
// unheaded continuation pages are covered deterministically in Pick Pages (every selected page is padded with page N+1) - do not reintroduce a next-page rule in this prompt
const prompt='These images are the pages of a UK company accounts filing from Companies House, in their original order. Every image has a black banner at the very top reading IMG n OF m - n is the image\'s position in the sequence. Report IMG numbers only. Numbers printed inside the document pages (headers or footers) are page numbers, NOT IMG numbers - ignore them completely.\n\nIdentify the pages containing:\n1. The profit and loss account or income statement (both group/consolidated AND company versions if both exist)\n2. EVERY page whose heading includes "Balance sheet" or "Statement of financial position" - list them all: group AND company versions, and continuation pages (a heading like "Balance sheet (continued)" counts).\n3. The note stating the average number of employees\n4. The cover or title page showing the financial year end date\n\nRespond with a single line in exactly this format:\nPAGES: <first>,<second>,<third>\nThe PAGES: line must contain IMG numbers only, each listed once, separated by commas. No ranges. No other text.';
const numCtx=Math.min(CTX_CAP,Math.max(8192,Math.ceil((images.length*SURVEY_TOKENS_PER_PAGE+CTX_HEADROOM)/CTX_STEP)*CTX_STEP));
// think:false is currently ignored by this qwen3-vl:32b build (always-thinking variant) - num_predict must budget the full thinking transcript
return[{json:{surveyBody:JSON.stringify({model:'qwen3-vl:32b',prompt:prompt,images:images,stream:false,think:false,options:{num_ctx:numCtx,num_predict:NUM_PREDICT}}),pageCount:images.length}}];

const j=($input.first().json)||{};
const resp=j.response||'';
const lenStop=j.done_reason==='length'?' [generation hit num_predict limit - page list may be truncated]':'';
let pageCount=0;try{pageCount=$('Prep Survey Prompt').first().json.pageCount||0;}catch(e){}
const m=resp.match(/PAGES:\s*([0-9,\s\-]+)/i);
if(!m||!pageCount)return[{json:{images:[],debug:'survey gave no usable PAGES line'+lenStop+': '+resp.slice(0,200)}}];
const nums=[];
m[1].split(',').forEach(function(tok){tok=tok.trim();if(!tok)return;const r=tok.match(/^(\d+)\s*-\s*(\d+)$/);if(r){const a=parseInt(r[1],10);const b=parseInt(r[2],10);if(b>=a&&b-a<=5){for(let p=a;p<=b;p++)nums.push(p);}return;}const n=parseInt(tok,10);if(!isNaN(n))nums.push(n);});
const valid=nums.filter(function(n){return n>=1&&n<=pageCount;});
const uniq=[];for(let i=0;i<valid.length;i++){if(uniq.indexOf(valid[i])===-1)uniq.push(valid[i]);}
uniq.sort(function(a,b){return a-b;});
if(uniq.length===0)return[{json:{images:[],debug:'survey PAGES line had no valid page numbers: '+resp.slice(0,200)}}];
if(uniq.length>12)return[{json:{images:[],debug:'survey selected '+uniq.length+' pages (max 12)'}}];
// pad +1 and +2: +1 covers unheaded continuation pages, +2 covers the model reporting printed footer numbers instead of banner numbers (observed under the old PAGE n OF m banner; retained pending A/B evidence under the IMG n OF m banner - compare rawPicks against figure-bearing pages before removing)
const CONVERTER_MAX_PAGES=20; // pdf-to-image /convert rejects pages lists longer than 20
function pad(base,depth){const out=base.slice();base.forEach(function(p){for(let d=1;d<=depth;d++){if(p+d<=pageCount&&out.indexOf(p+d)===-1)out.push(p+d);}});out.sort(function(a,b){return a-b;});return out;}
let padDropped='';
let padDepth=2;
let pages=pad(uniq,2);
if(pages.length>CONVERTER_MAX_PAGES){padDepth=1;pages=pad(uniq,1);padDropped=' [depth-2 padding dropped: exceeds '+CONVERTER_MAX_PAGES+'-page converter limit]';}
if(pages.length>CONVERTER_MAX_PAGES){padDepth=0;pages=uniq;padDropped=' [all padding dropped: exceeds '+CONVERTER_MAX_PAGES+'-page converter limit]';}
const src=$('CH: Download PDF').first();
const bin=(src.binary||{}).pdfData;
if(!bin)return[{json:{images:[],debug:'No PDF binary available for key-page conversion'}}];
const okOut={selectedPages:pages.join(','),padDepth:padDepth,rawPicks:uniq.join(',')};
if(lenStop||padDropped)okOut.debug='survey'+lenStop+padDropped;
return[{json:okOut,binary:{pdfData:bin}}];

const companyNumber=$('CH: Company').first().json.company_number;
const parseItems=$('Parse Input').all();
if(!companyNumber)throw new Error('Companies House returned no company for this entry - check the number.');
const matched=parseItems.find(function(item){return item.json.companyNumber&&item.json.companyNumber.toUpperCase()===companyNumber.toUpperCase();});
if(!matched)throw new Error('Company '+companyNumber+' returned by Companies House does not match any parsed input entry - aborting rather than inventing ranking/products.');
const input=matched.json;
const company=$('CH: Company').first().json;
const officers=$('CH: Officers').first().json;
const webData=$input.first().json;
let financials={turnover:null,employees:null,netAssets:null,profitBeforeTax:null,profitAfterTax:null,accountsYear:null,basis:null};
try {
  let xbrlDirect = null;
  try {
    const xbrlNode = $('Extract iXBRL Text').first();
    if (xbrlNode && xbrlNode.json && xbrlNode.json.xbrlExtracted && xbrlNode.json.ollamaBody === null) {
      xbrlDirect = xbrlNode.json.xbrlExtracted;
    }
  } catch(xe) {}

  if (xbrlDirect) {
    financials = {
      turnover:      xbrlDirect.turnover,
      employees:     xbrlDirect.employees,
      netAssets:     xbrlDirect.netAssets,
      profitBeforeTax:xbrlDirect.profitBeforeTax,
      profitAfterTax:xbrlDirect.profitAfterTax,
      accountsYear:  xbrlDirect.yearEnd,
      basis:         (xbrlDirect.basis||null)
    };
  } else {
    const finRaw = $('HTTP: Extract Financials').first().json;
    if (finRaw && finRaw.response) {
      const text = finRaw.response;
      try {
        const parsed = JSON.parse(text);
        financials = {
          turnover:      parsed.turnover||null,
          employees:     parsed.employees||null,
          netAssets:     parsed.netAssets||null,
          profitBeforeTax:parsed.profitBeforeTax||parsed.pretaxProfit||null,
          profitAfterTax:parsed.profitAfterTax||parsed.profit||null,
          accountsYear:  parsed.year||null
        };
      } catch(e) {
        const lines = text.split(/\r?\n/);
        const getNum = function(key){
          const line = lines.find(function(l){return l.toLowerCase().startsWith(key.toLowerCase());});
          if (!line) return null;
          const neg = line.includes('-') || line.includes('(');
          const n = parseInt(line.slice(key.length).replace(/[^0-9]/g,''));
          return isNaN(n) ? null : (neg ? -n : n);
        };
        const yearLine = lines.find(function(l){return l.toLowerCase().startsWith('year:');});
        const yM = yearLine ? yearLine.match(/(20\d\d|19\d\d)/) : null;
        financials = {
          turnover:      getNum('Turnover:'),
          employees:     getNum('Employees:'),
          netAssets:     getNum('Net assets:'),
          profitBeforeTax:getNum('Profit before tax:'),
          profitAfterTax:(getNum('Profit after tax:')!==null?getNum('Profit after tax:'):getNum('Profit:')),
          accountsYear:  yM?yM[1]:null
        };
      }
    }
  }
} catch(e) {}
const webResults=(webData.results||[]).slice(0,3);
const webSnippets=webResults.map(function(r){return(r.title||'')+': '+(r.content||'').substring(0,150);});
const reg=company.registered_office_address||{};
const address=[reg.address_line_1,reg.locality,reg.postal_code].filter(Boolean).join(', ');
const region=reg.county||reg.region||reg.locality||'';
const dirs=(officers.items||[]).filter(function(o){return!o.resigned_on;}).map(function(o){return o.name+' ('+o.officer_role+')';}).slice(0,5);
let accountsConfidence='none';
try{const metaUrl=$('Get Filing URL').first().json.metaUrl;if(metaUrl){const fmt=$('Detect Format').first().json.format;accountsConfidence=fmt==='ixbrl'?'high':'low';}}catch(e){}
if(financials&&!financials.basis){try{const _xn=$('Extract iXBRL Text').first();if(_xn&&_xn.json&&_xn.json.xbrlExtracted&&_xn.json.xbrlExtracted.basis)financials.basis=_xn.json.xbrlExtracted.basis;}catch(_e){}}
const profile={companyNumber:input.companyNumber,companyName:company.company_name||'',address:address,region:region,sicCodes:company.sic_codes||[],incorporated:company.date_of_creation||null,status:company.company_status||'',directors:dirs,customerRanking:input.ranking,products:input.products,financials:financials,accountsConfidence:accountsConfidence,rankingNote:input.note||'',webSnippets:webSnippets,profileDate:new Date().toISOString().split('T')[0]};
const store=$getWorkflowStaticData('global');
Object.keys(store.profiles||{}).forEach(function(k){var ck=/^\d{1,7}$/.test(k)?k.padStart(8,'0'):k;if(ck!==k){if(!store.profiles[ck]){store.profiles[ck]=store.profiles[k];store.profiles[ck].companyNumber=ck;}delete store.profiles[k];}});
if(!store.profiles)store.profiles={};
store.profiles[input.companyNumber]=profile;
